mapper.select:
SELECT s.student_id, s.user_id, s.student_no, s.name, s.gender, oc.org_name AS college_name, ok.org_name AS class_name, s.grade, s.phone, s.email FROM student_info s LEFT JOIN organization oc ON oc.org_id = s.college_id LEFT JOIN organization ok ON ok.org_id = s.class_id
AND (s.student_no LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') OR s.phone LIKE CONCAT('%', #{keyword}, '%'))
AND s.college_id = #{collegeId}
AND s.class_id = #{classId}
AND s.grade = #{grade}
ORDER BY s.student_no ASC
